import { retrieveCustomer } from "@/lib/data/customer"
import { getSiteConfig } from "@/lib/site-config"
import { fetchGameListingCounts } from "@/lib/api/customer-backend"
import { HeroSection } from "@/components/homepage/HeroSection"
import { GameSelectorGrid } from "@/components/homepage/GameSelectorGrid"
import { TrustSection } from "@/components/homepage/TrustSection"
import { SellerCTABanner } from "@/components/homepage/SellerCTABanner"
import type { Metadata } from "next"

export const metadata: Metadata = {
  title: "SideDecked - The TCG Marketplace",
  description:
    "The TCG marketplace for Magic, Pokémon, Yu-Gi-Oh!, and One Piece players. Buy, sell, and build decks.",
  openGraph: {
    title: "SideDecked - The TCG Marketplace",
    description:
      "The TCG marketplace for Magic, Pokémon, Yu-Gi-Oh!, and One Piece players. Buy, sell, and build decks.",
    url: process.env.NEXT_PUBLIC_BASE_URL,
    siteName: "SideDecked - TCG Marketplace",
    type: "website",
    images: [
      {
        url: "/B2C_Storefront_Open_Graph.png",
        width: 1200,
        height: 630,
        alt: "SideDecked - The TCG Marketplace",
      },
    ],
  },
}

export default async function Home({
  params,
}: {
  params: Promise<{ locale: string }>
}) {
  const { locale: _locale } = await params

  const [customer, config, listingCounts] = await Promise.all([
    retrieveCustomer().catch(() => null),
    getSiteConfig(),
    fetchGameListingCounts(),
  ])

  const isAuthenticated = !!customer

  return (
    <main>
      <HeroSection
        cardCount={config.cardCount}
        sellerCount={config.sellerCount}
        avgSellerRating={config.avgSellerRating}
      />
      <GameSelectorGrid counts={listingCounts?.counts} />
      {/* TrendingStrip slot — wire up when GET /api/cards/trending is available */}
      <TrustSection cardCount={config.cardCount} />
      <SellerCTABanner isAuthenticated={isAuthenticated} />
    </main>
  )
}

