        <rect width="18" height="18" x="3" y="3" rx="2" />
        <path d="M7 7h10" />
        <path d="M7 12h10" />
        <path d="M7 17h10" />
      </svg>
    ),
    valueKey: "cardCount" as const,
    valueSuffix: "+",
    label: "Cards across 4 games, updated daily",
  },
  {
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10" />
        <path d="m9 12 2 2 4-4" />
      </svg>
    ),
    staticValue: "Verified Sellers",
    label: "Every seller reviewed and graded",
  },
  {
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10" />
      </svg>
    ),
    staticValue: "Buyer Protection",
    label: "Every transaction covered",
  },
]

export function TrustSection({ cardCount }: TrustSectionProps) {
  return (
    <section aria-label="Why SideDecked" className="px-5 py-10 sm:px-12 lg:py-16">
      <div className="mx-auto max-w-[1344px]">
        <p className="mb-7 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow">
          Why SideDecked
        </p>
        <div className="grid gap-3 sm:gap-4 lg:grid-cols-3">
          {TRUST_CARDS.map((card, i) => {
            const value =
              card.valueKey === "cardCount"
                ? `${cardCount}${card.valueSuffix ?? ""}`
                : card.staticValue

            return (
              <div
                key={i}
                className="relative overflow-hidden rounded-2xl border border-border p-6 text-center sm:p-9"
                style={{
                  background: "rgba(24, 22, 42, 0.40)",
                  backdropFilter: "blur(8px)",
                }}
              >
                {/* Top glow line */}
                <div
                  className="absolute left-1/2 top-0 h-px w-[120px] -translate-x-1/2"
                  style={{
                    background:
                      "linear-gradient(90deg, transparent, var(--brand-primary, #8B5CF6), transparent)",
                  }}
                />

                {/* Icon */}
                <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-[14px] border border-primary/15 bg-primary/10 text-primary">
                  <div className="h-[22px] w-[22px]">{card.icon}</div>
                </div>

                {/* Value */}
                <p className="mb-1 font-barlow-condensed text-[26px] font-bold text-primary lg:text-[32px]">
                  {value}
                </p>

                {/* Label */}
                <p className="text-[13px] leading-relaxed text-secondary sm:text-sm">
                  {card.label}
                </p>
              </div>
            )
          })}
        </div>
      </div>
    </section>
  )
}

