  set: string
  price: number
  imageUrl?: string
}

interface TrendingStripProps {
  cards?: TrendingCard[]
}

function CardPlaceholder() {
  return (
    <div className="flex h-full w-full flex-col items-center justify-center gap-2 bg-gradient-to-br from-bg-surface-2 to-bg-surface-3">
      <svg
        className="h-10 w-10 text-tertiary opacity-40"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.5"
      >
        <rect x="3" y="3" width="18" height="18" rx="2" />
        <circle cx="8.5" cy="8.5" r="1.5" />
        <path d="m21 15-5-5L5 21" />
      </svg>
    </div>
  )
}

export function TrendingStrip({ cards }: TrendingStripProps) {
  if (!cards || cards.length === 0) return null

  return (
    <section aria-label="Trending cards" className="py-8 sm:py-12">
      <p className="mb-6 px-5 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow sm:px-12">
        Trending Now
      </p>
      <div
        className={cn(
          "flex gap-4 overflow-x-auto px-5 pb-4 sm:gap-5 sm:px-12",
          "scrollbar-thin scrollbar-track-transparent scrollbar-thumb-bg-surface-3"
        )}
      >
        {cards.map((card) => (
          <Link
            key={card.id}
            href={`/cards/${card.id}`}
            className="group flex-shrink-0 transition-transform duration-150 [@media(pointer:fine)]:hover:-translate-y-1"
            style={{ width: 180 }}
          >
            <div className="mb-2.5 overflow-hidden rounded-xl border border-border bg-bg-surface-2" style={{ aspectRatio: "5/7" }}>
              {card.imageUrl ? (
                <img
                  src={card.imageUrl}
                  alt={card.name}
                  className="h-full w-full object-contain"
                />
              ) : (
                <CardPlaceholder />
              )}
            </div>
            <p className="truncate font-barlow text-[13px] font-semibold text-primary">
              {card.name}
            </p>
            <p className="truncate text-xs text-tertiary">{card.set}</p>
            <p className="font-dm-mono text-sm font-medium text-positive">
              ${card.price.toFixed(2)}
            </p>
          </Link>
        ))}
      </div>
    </section>
  )
}

/**
 * Customer Backend API Client
 * Handles communication with the customer-backend service for TCG catalog, 
 * deck builder, community, and other customer-specific features.
 */

import { 
  Card, 
  SearchQuery, 
  SearchResponse, 
  Game, 
  CardSet, 
  Print,
  CatalogSKU,
  Format,
  SearchSuggestion,
  SearchAnalytics,
  SearchTrend,
  PopularSearch
} from "@/types/tcg"
import { getUniversalAuthHeaders } from "@/lib/utils/auth-helpers"

// Types for inventory functionality
export interface InventoryCheckResult {
  available: boolean
  quantity: number
  reserved_quantity: number
  can_backorder: boolean
  is_managed: boolean
  last_checked: string // ISO date string
  location_breakdown?: InventoryLocationLevel[]
}

export interface InventoryLocationLevel {
  location_id: string
  stocked_quantity: number
  reserved_quantity: number
  incoming_quantity: number
}

export interface InventoryApiResponse {
  success: boolean
  data: InventoryCheckResult & { variant_id: string }
  timestamp: string
  error?: string
}

export interface BatchInventoryApiResponse {
  success: boolean
  data: Record<string, InventoryCheckResult>
  meta: {
    requested_count: number
    retrieved_count: number
    cache_enabled: boolean
    locations_included: boolean
  }
  timestamp: string
  error?: string
}

export interface ApiErrorResponse {
  success: false
  error: string
  message: string
  timestamp: string
  details?: any[]
}

const CUSTOMER_BACKEND_URL = 
  process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL || "http://localhost:7000"

// Retry configuration
interface RetryConfig {
  maxAttempts: number
  initialDelayMs: number
  maxDelayMs: number
  backoffMultiplier: number
}

const DEFAULT_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 3,
  initialDelayMs: 1000,
  maxDelayMs: 30000,
  backoffMultiplier: 2
}

// Extended retry config for cold starts
const COLD_START_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 4,
  initialDelayMs: 2000,
  maxDelayMs: 60000,
  backoffMultiplier: 2.5
}

class CustomerBackendAPI {
  private baseUrl: string
  private defaultHeaders: HeadersInit
  private isRecovering: boolean = false
  private recoveryCallbacks: Array<(status: 'recovered' | 'failed') => void> = []

  constructor() {
    this.baseUrl = CUSTOMER_BACKEND_URL
    this.defaultHeaders = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    }
  }

  /**
   * Check if service is available (cold start detection)
   */
  async checkHealth(): Promise<boolean> {
    try {
      const response = await fetch(`${this.baseUrl}/ping`, {
        method: 'GET',
        signal: AbortSignal.timeout(5000) // 5 second timeout for health check
      })
      return response.ok
    } catch {
      return false
    }
  }

  /**
   * Wait for a specified delay
   */
  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms))
  }

  /**
   * Calculate exponential backoff delay
   */
  private calculateBackoff(attempt: number, config: RetryConfig): number {
    const delay = Math.min(
      config.initialDelayMs * Math.pow(config.backoffMultiplier, attempt - 1),
      config.maxDelayMs
    )
    // Add jitter to prevent thundering herd
    return delay + Math.random() * 1000
  }

  /**
   * Detect if error is likely a cold start
   */
  private isColdStartError(error: any): boolean {
    if (error instanceof TypeError && error.message.includes('fetch failed')) {
      return true
    }
    if (error.name === 'AbortError' || error.message?.includes('timeout')) {
      return true
    }
    if (error.message?.includes('ECONNREFUSED') || error.message?.includes('ENOTFOUND')) {
      return true
    }
    return false
  }

  /**
   * Make request with retry logic
   */
  private async requestWithRetry<T>(
    endpoint: string,
    options: RequestInit = {},
    retryConfig?: RetryConfig
  ): Promise<T> {
    const config = retryConfig || DEFAULT_RETRY_CONFIG
    let lastError: any
    let isColdStart = false

    // Get authentication headers (works in both server and client context)
    const authHeaders = await getUniversalAuthHeaders()

    for (let attempt = 1; attempt <= config.maxAttempts; attempt++) {
      try {
        // Add timeout to prevent hanging requests
        const timeout = attempt === 1 ? 10000 : 30000 // 10s first attempt, 30s for retries
        const response = await fetch(`${this.baseUrl}${endpoint}`, {
          ...options,
          headers: {
            ...this.defaultHeaders,
            ...authHeaders,
            ...options.headers,
          },
          signal: AbortSignal.timeout(timeout)
        })

        if (!response.ok) {
          const errorText = await response.text()
          throw new Error(`API Error ${response.status}: ${errorText}`)
        }

        const data = await response.json()
        
        // If we recovered from cold start, notify callbacks
        if (isColdStart && this.isRecovering) {
          this.isRecovering = false
          this.recoveryCallbacks.forEach(cb => cb('recovered'))
          this.recoveryCallbacks = []
        }
        
        return data
      } catch (error) {
        lastError = error
        
        // Check if this looks like a cold start
        if (attempt === 1 && this.isColdStartError(error)) {
          isColdStart = true
          this.isRecovering = true
        }

        // Don't retry on client errors (4xx)
        if (error instanceof Error && error.message.includes('API Error 4')) {
          throw error
        }

        // If not last attempt, wait and retry
        if (attempt < config.maxAttempts) {
          const backoffDelay = this.calculateBackoff(attempt, config)
          console.log(
            `Request to ${endpoint} failed (attempt ${attempt}/${config.maxAttempts}),` +
            ` retrying in ${Math.round(backoffDelay / 1000)}s...`
          )
          await this.delay(backoffDelay)
        }
      }
    }

    // All retries failed
    if (this.isRecovering) {
      this.isRecovering = false
      this.recoveryCallbacks.forEach(cb => cb('failed'))
      this.recoveryCallbacks = []
    }

    console.error(`All retry attempts failed for ${endpoint}:`, lastError)
    throw lastError
  }

  private async request<T>(
    endpoint: string, 
    options: RequestInit = {}
  ): Promise<T> {
    // Use extended retry config for critical endpoints during cold starts
    const isCriticalEndpoint = [
      '/api/games',
      '/api/health',
      '/ping',
      '/api/search/facets'
    ].some(path => endpoint.includes(path))

    const retryConfig = isCriticalEndpoint ? COLD_START_RETRY_CONFIG : DEFAULT_RETRY_CONFIG
    
    return this.requestWithRetry<T>(endpoint, options, retryConfig)
  }

  /**
   * Subscribe to recovery status updates
   */
  onRecoveryStatusChange(callback: (status: 'recovered' | 'failed') => void): () => void {
    this.recoveryCallbacks.push(callback)
    // Return unsubscribe function
    return () => {
      this.recoveryCallbacks = this.recoveryCallbacks.filter(cb => cb !== callback)
    }
  }

  /**
   * Check if currently recovering from cold start
   */
  isRecoveringFromColdStart(): boolean {
    return this.isRecovering
  }

  // Games API
  async getGames(): Promise<Game[]> {
    return this.request<Game[]>('/api/games')
  }

  async getGame(gameId: string): Promise<Game> {
    return this.request<Game>(`/api/games/${gameId}`)
  }

  async getGameByCode(code: string): Promise<Game> {
    return this.request<Game>(`/api/games/code/${code}`)
  }

  // Cards API
  async searchCards(query: SearchQuery): Promise<SearchResponse> {
    const searchParams = new URLSearchParams()
    
    if (query.text) {
      searchParams.append('q', query.text)
    }
    
    if (query.filters) {
      Object.entries(query.filters).forEach(([key, value]) => {
        if (Array.isArray(value)) {
          value.forEach(v => searchParams.append(key, v))
        } else if (typeof value === 'object' && value !== null) {
          // Handle range filters like manaValue: { min: 1, max: 5 }
          Object.entries(value).forEach(([rangeKey, rangeValue]) => {
            if (rangeValue !== undefined && rangeValue !== null) {
              searchParams.append(`${key}.${rangeKey}`, rangeValue.toString())
            }
          })
        } else if (value !== undefined) {
          searchParams.append(key, value.toString())
        }
      })
    }
    
    searchParams.append('sort', query.sort || 'relevance')
    searchParams.append('page', query.page.toString())
    searchParams.append('limit', (query.limit || query.pageSize || 20).toString())

    return this.request<SearchResponse>(`/api/cards/search?${searchParams}`)
  }

  async getCard(cardId: string): Promise<Card> {
    return this.request<Card>(`/api/cards/${cardId}`)
  }

  async getCardByOracleId(oracleId: string): Promise<Card> {
    return this.request<Card>(`/api/cards/oracle/${oracleId}`)
  }

  async getCardDetails(cardId: string): Promise<Card & {
    prints: Print[]
    sets: CardSet[]
    legality: Record<string, boolean>
  }> {
    return this.request(`/api/cards/${cardId}/details`)
  }

  async getPopularCards(gameCode?: string, limit: number = 20): Promise<Card[]> {
    const params = new URLSearchParams()
