  // Inventory API
  /**
   * Check inventory for a single product variant
   */
  async checkInventory(
    variantId: string, 
    options: {
      useCache?: boolean
      includeLocations?: boolean
    } = {}
  ): Promise<InventoryCheckResult> {
    const { useCache = true, includeLocations = false } = options
    
    try {
      const params = new URLSearchParams({
        useCache: useCache.toString(),
        includeLocations: includeLocations.toString()
      })

      const response = await this.request<InventoryApiResponse>(
        `/api/commerce/inventory/${variantId}?${params}`
      )

      if (!response.success) {
        throw new Error(response.error || 'Failed to check inventory')
      }

      return response.data
    } catch (error) {
      console.warn('Inventory check failed, using fallback', { variantId, error })
      return this.getFallbackInventoryResult()
    }
  }

  /**
   * Check inventory for multiple product variants (batch operation)
   */
  async checkMultipleInventory(
    variantIds: string[],
    options: {
      useCache?: boolean
      includeLocations?: boolean
    } = {}
  ): Promise<Map<string, InventoryCheckResult>> {
    if (variantIds.length === 0) {
      return new Map()
    }

    const { useCache = true, includeLocations = false } = options
    
    try {
      const response = await this.request<BatchInventoryApiResponse>(
        '/api/commerce/inventory/check',
        {
          method: 'POST',
          body: JSON.stringify({
            variantIds,
            useCache,
            includeLocations
          })
        }
      )

      if (!response.success) {
        throw new Error(response.error || 'Failed to check multiple inventory')
      }

      // Convert object to Map
      const results = new Map<string, InventoryCheckResult>()
      for (const [variantId, result] of Object.entries(response.data)) {
        results.set(variantId, result)
      }

      return results
    } catch (error) {
      console.warn('Batch inventory check failed, using fallback', { 
        variantCount: variantIds.length, 
        error 
      })
      
      const fallbackResults = new Map<string, InventoryCheckResult>()
      for (const variantId of variantIds) {
        fallbackResults.set(variantId, this.getFallbackInventoryResult())
      }
      return fallbackResults
    }
  }

  /**
   * Invalidate inventory cache for specific variants
   * Used after purchases or inventory updates
   */
  async invalidateInventoryCache(variantIds: string[]): Promise<void> {
    if (variantIds.length === 0) return

    try {
      await this.request('/api/commerce/inventory/invalidate', {
