  // Deck Builder API
  async getDecks(userId?: string, games?: string[]): Promise<any[]> {
    if (!userId) {
      // If no userId provided, we can't fetch user-specific decks
      throw new Error('User ID is required to fetch decks')
    }

    const searchParams = new URLSearchParams()
    
    if (games && games.length > 0) {
      games.forEach(game => searchParams.append('game', game))
    }
    
    const params = searchParams.toString() ? `?${searchParams.toString()}` : ''
    
    try {
      const response = await this.request<any>(`/api/decks/user/${userId}${params}`)
      
      // Handle the response format from the backend API
      if (response.success && response.data?.decks) {
        return response.data.decks
      } else if (response.success && Array.isArray(response.data)) {
        return response.data
      } else {
        return []
      }
    } catch (error: any) {
      // If it's a 404, the user simply has no decks - return empty array
      if (error.message?.includes('404')) {
        return []
      }
      // Re-throw other errors
      throw error
    }
  }

  async getPublicDecks(
    filters?: {
      games?: string[]
      format?: string
      sort?: string
      page?: number
      limit?: number
    }
