    if (filters) {
      if (filters.games && filters.games.length > 0) {
        filters.games.forEach(game => searchParams.append('game', game))
      }
      if (filters.format) searchParams.append('format', filters.format)
      if (filters.sort) searchParams.append('sort', filters.sort)
      if (filters.page) searchParams.append('page', filters.page.toString())
      if (filters.limit) searchParams.append('limit', filters.limit.toString())
    }
    
    const params = searchParams.toString() ? `?${searchParams.toString()}` : ''
    
    try {
      const response = await this.request<any>(`/api/decks/public${params}`)
      
      if (response.success && response.data?.decks) {
        return response.data
      } else if (response.success && Array.isArray(response.data)) {
        return { decks: response.data, pagination: null }
      } else {
        return { decks: [], pagination: null }
      }
    } catch (error: any) {
      console.error('Failed to fetch public decks:', error)
      return { decks: [], pagination: null }
    }
  }

