router.get('/catalog/listing-counts', async (_req, res) => {
  try {
    const redis = getRedisClient()
    const cacheKey = 'listing-counts:by-game'

    // Redis read is best-effort: treat failures as a cache miss so DB can serve
    try {
      const cached = await redis.get(cacheKey)
      if (cached) {
        return res.json(JSON.parse(cached))
      }
    } catch (cacheReadError) {
      console.warn('Redis read failed for listing-counts, falling through to DB:', cacheReadError)
    }

    const rows: Array<{ game_code: string; count: string }> = await AppDataSource.query(`
      SELECT game_code, COUNT(*) AS count
      FROM catalog_skus
      WHERE (has_c2c_listings = true OR has_b2c_inventory = true)
        AND is_active = true AND deleted_at IS NULL
      GROUP BY game_code
    `)

    const counts: Record<string, number> = {}
    for (const row of rows) {
      counts[row.game_code] = Number(row.count)
    }

    const result = { counts, cachedAt: new Date().toISOString() }

    // Redis write is best-effort: don't fail the request if cache is unavailable
    try {
      await redis.set(cacheKey, JSON.stringify(result), 'EX', 30)
    } catch (cacheWriteError) {
      console.error('Error writing listing counts to cache:', cacheWriteError)
    }

    return res.json(result)
  } catch (error) {
    console.error('Error fetching listing counts:', error)
    return res.status(503).json({
      success: false,
      error: { code: 'SERVICE_UNAVAILABLE', message: 'Listing count service temporarily unavailable' },
      timestamp: new Date().toISOString(),
    })
  }
})

